const headers = $input.item.json.headers || {};
const body = $input.item.json.body || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { _unauthorized: true, status: 401 } };
if (!body.carrier_id || !body.period || body.statement_amount_cents === undefined) return { json: { _empty: true, status: 400, error: 'carrier_id + period (YYYY-MM) + statement_amount_cents required' } };
if (!/^\d{4}-\d{2}$/.test(body.period)) return { json: { _empty: true, status: 400, error: 'period must be YYYY-MM format' } };
return { json: { token, body } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : (rows && (rows.user_id || rows.id) ? rows : null);
if (!row) return { json: { _unauthorized: true, status: 401 } };
if (row.user_role !== 'admin') return { json: { _unauthorized: true, status: 403, error: 'admin role required' } };
const body = $('Extract').first().json.body;
return { json: { _ok: true, body: body, user_id: row.user_id, client_id: row.client_id } };

// Compute the period date range for matching expected commissions.
const body = $input.item.json.body;
const period = body.period;  // 'YYYY-MM'
const startDate = period + '-01';
const y = parseInt(period.slice(0, 4), 10);
const m = parseInt(period.slice(5, 7), 10);
const lastDay = new Date(y, m, 0).getDate();
const endDate = period + '-' + String(lastDay).padStart(2, '0');
return { json: Object.assign({}, $input.item.json, { period_start: startDate, period_end: endDate }) };

// Compare statement amount vs sum of expected commissions in this period.
const expected = $input.item.json;
const list = Array.isArray(expected) ? expected : [];
const ctx = $('Compute Range').first().json;
const body = ctx.body;
let expectedTotal = 0;
list.forEach(function (c) { expectedTotal += parseInt(c.expected_amount_cents) || 0; });
const statementAmount = parseInt(body.statement_amount_cents);
const delta = statementAmount - expectedTotal;
let status;
if (Math.abs(delta) < 100) status = 'matched';                  // within $1 = matched
else if (delta > 0 && expectedTotal === 0) status = 'pending';   // statement received but no expectations
else if (Math.abs(delta) < (expectedTotal * 0.05)) status = 'matched';  // within 5%
else if (delta < 0) status = 'discrepancy';                      // underpaid materially
else status = 'partial';                                          // overpaid or extra payments
const now = new Date().toISOString();
const row = {
  client_id: ctx.client_id,
  carrier_id: body.carrier_id,
  reconciliation_period: body.period,
  statement_received_at: now,
  statement_amount_cents: statementAmount,
  matched_commissions_cents: expectedTotal,
  status: status,
  statement_url: body.statement_url || null,
  reconciled_by: ctx.user_id,
  reconciled_at: now,
  notes: 'Auto-matched: ' + list.length + ' expected commission rows totalling ' + expectedTotal + ' cents; statement ' + statementAmount + ' cents; delta ' + delta + ' cents.'
};
return { json: { _ok: true, row: row, matched_commission_ids: list.map(function (c) { return c.id; }), expectedTotal: expectedTotal, statementAmount: statementAmount, delta: delta, status: status } };

// Now mark matched expected commissions as 'received' (status flip).
const recon = $input.item.json;
const reconRow = Array.isArray(recon) ? recon[0] : recon;
const ids = $('Compute Match').first().json.matched_commission_ids || [];
if (!ids.length) return { json: { _no_match: true, reconciliation: reconRow } };
// PATCH each commission row to mark received.
return { json: { reconciliation_id: reconRow.id, ids: ids, reconciliation: reconRow } };

const match = $('Compute Match').first().json;
const reconRow = $('Prepare Patch').first().json.reconciliation;
return { json: { ok: true, reconciliation: reconRow, summary: { expected_total_cents: match.expectedTotal, statement_amount_cents: match.statementAmount, delta_cents: match.delta, status: match.status, commissions_marked_received: ($('Prepare Patch').first().json.ids || []).length } } };
